class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testEmptyContextIsActive() {
        assertTrue(EmptyCoroutineContext.isActive)
    }

    @Test
    fun testJoblessContextIsActive() {
        val ctx: CoroutineContext = Dispatchers.Default + CoroutineName("test")
        assertTrue(ctx.isActive)
    }

    @Test
    fun testContextWithJobTracksJobState() {
        val job = Job()
        val ctx: CoroutineContext = job + CoroutineName("test")
        assertTrue(ctx.isActive)
        job.cancel()
        assertFalse(ctx.isActive)
    }
}
